  esac
}
oraclefunc() {  # Oracle-compatibility functions (MariaDB supports them)
  n3; local _c=$REPLY
  case $(( RANDOM % 6 + 1 )) in
    1) n10; REPLY="CHR(${REPLY})";;
    2) REPLY="TO_CHAR(c${_c})";;
    3) REPLY="TO_CHAR(c${_c}, 'YYYY-MM-DD')";;
    4) REPLY="TO_NUMBER(c${_c})";;
    5) az; REPLY="SFORMAT('Value={}', c${_c})";;
    6) REPLY="NATURAL_SORT_KEY(c${_c})";;
    *) REPLY="CHR(65)";;
  esac
}
convertusing() {  # CONVERT ... USING charset
  n3; local _c=$REPLY
  case $(( RANDOM % 4 + 1 )) in
    1) REPLY="CONVERT(c${_c} USING utf8mb4)";; 2) REPLY="CONVERT(c${_c} USING latin1)";;
    3) REPLY="CONVERT(c${_c} USING binary)";; 4) REPLY="CAST(c${_c} AS CHAR CHARACTER SET utf8mb4)";;
    *) REPLY="CONVERT(c${_c} USING utf8mb4)";;
  esac
}
# ========================================= Partitioning helpers (greatly expanded)
systimepart() {  # PARTITION BY SYSTEM_TIME variants (MariaDB system-versioned)
  case $(( RANDOM % 8 + 1 )) in
    1) REPLY="PARTITION BY SYSTEM_TIME(PARTITION p_hist HISTORY, PARTITION p_cur CURRENT)";;
    2) REPLY="PARTITION BY SYSTEM_TIME LIMIT $((RANDOM % 52)) (PARTITION p0 HISTORY, PARTITION p1 HISTORY, PARTITION pcur CURRENT)";;
    3) REPLY="PARTITION BY SYSTEM_TIME INTERVAL $((RANDOM % 365 + 1)) DAY(PARTITION p0 HISTORY, PARTITION pcur CURRENT)";;
    4) REPLY="PARTITION BY SYSTEM_TIME INTERVAL $((RANDOM % 12 + 1)) WEEK(PARTITION p0 HISTORY, PARTITION p1 HISTORY, PARTITION p2 HISTORY, PARTITION pcur CURRENT)";;
    5) REPLY="PARTITION BY SYSTEM_TIME INTERVAL $((RANDOM % 24 + 1)) MONTH(PARTITION p0 HISTORY, PARTITION pcur CURRENT)";;
    6) REPLY="PARTITION BY SYSTEM_TIME INTERVAL $((RANDOM % 48 + 1)) HOUR AUTO";;
    7) REPLY="PARTITION BY SYSTEM_TIME INTERVAL $((RANDOM % 24 + 1)) MONTH STARTS '2020-01-01 00:00:00' AUTO PARTITIONS $((RANDOM % 32 + 1))";;
    8) REPLY="PARTITION BY SYSTEM_TIME LIMIT $((RANDOM % 52)) AUTO";;
    *) REPLY="PARTITION BY SYSTEM_TIME(PARTITION p_hist HISTORY, PARTITION p_cur CURRENT)";;
  esac
}
partdatadir() {  # DATA DIRECTORY and INDEX DIRECTORY for partitions (low freq; often not allowed)
  if (( RANDOM % 20 == 0 )); then REPLY="DATA DIRECTORY='/tmp/partdata' INDEX DIRECTORY='/tmp/partidx'"; else REPLY=""; fi
}
partspec() {  # Single partition specification (for ADD PARTITION, REORGANIZE INTO)
  n100; local _v1=$REPLY; n100; local _v2=$REPLY; n3; local _n=$REPLY
  case $(( RANDOM % 5 + 1 )) in
    1) REPLY="(PARTITION p${_n} VALUES LESS THAN(${_v1}))";;
    2) REPLY="(PARTITION p${_n} VALUES LESS THAN MAXVALUE)";;
    3) REPLY="(PARTITION p${_n} VALUES IN (${_v1}, ${_v2}))";;
    4) REPLY="(PARTITION p${_n} VALUES LESS THAN(${_v1}) COMMENT='test part')";;
    5) REPLY="(PARTITION p${_n} VALUES LESS THAN(${_v1}) ENGINE=InnoDB)";;
    *) REPLY="(PARTITION p${_n} VALUES LESS THAN(${_v1}))";;
  esac
}
partlist2() {  # Comma-separated partition name list (for DROP, REBUILD, etc.)
  n3; local _n1=$REPLY; n3
  case $(( RANDOM % 4 + 1 )) in
    1) REPLY="p${_n1}";;
    2) REPLY="p${_n1}, p${REPLY}";;
    3) REPLY="ALL";;
    4) REPLY="p0, p1, p2";;
    *) REPLY="p${_n1}";;
  esac
}
