    7) n3; local _v1=$REPLY; n3; local _v2=$REPLY; table; local _v3=$REPLY; joinwon; local _v4=$REPLY; table; local _v5=$REPLY; whereal; REPLY="SELECT c$_v1,c$_v2 FROM $_v3 AS a1 $_v4 $_v5 AS a2 ON a1.c1=a2.c1 $REPLY";;
    8) n3; local _v1=$REPLY; table; local _v2=$REPLY; joinwon; local _v3=$REPLY; table; local _v4=$REPLY; joinwon; local _v5=$REPLY; table; local _v6=$REPLY; whereal; REPLY="SELECT c$_v1 FROM $_v2 AS a1 $_v3 $_v4 AS a2 ON a1.c1=a2.c1 $_v5 $_v6 AS a3 ON a2.c1=a3.c1 $REPLY";;
    9) case $(( RANDOM % 2 + 1 )) in
