        2) table; local _ft=$REPLY; n3; local _v1=$REPLY; table; local _v2=$REPLY; joinlron; local _v3=$REPLY; n3; local _v4=$REPLY; REPLY="SELECT a2.c$_v1 FROM $_v2 AS a1 $_v3 $_ft AS a2 ON a2.c$_v4 = a1.c$_v4";;
