        2) table; local _ft=$REPLY; n3; local _v1=$REPLY; table; local _v2=$REPLY; joinlron; local _v3=$REPLY; n3; local _v4=$REPLY; data; local _v5=$REPLY; REPLY="SELECT $_ft.c$_v1 FROM $_v2 $_v3 $_ft ON $_ft.c$_v4=$_v5";;
